 {"id":"asupersync-pm5vc","title":"[FS] Implement Async File Type and Operations","description":"# Async File Type and Operations

## Overview
Implement the core `File` type with async read, write, seek, and metadata operations.

## Implementation Steps

### Step 1: File Type
```rust
use std::os::fd::{AsRawFd, RawFd};
use std::path::Path;

pub struct File {
    inner: std::fs::File,
    // Registration with reactor for async I/O
}

impl File {
    /// Open file for reading
    pub async fn open(path: impl AsRef<Path>) -> io::Result<File> {
        let path = path.as_ref().to_owned();
        spawn_blocking(move || std::fs::File::open(path))
            .await?
            .map(|f| File { inner: f })
    }

    /// Create file for writing (truncates if exists)
    pub async fn create(path: impl AsRef<Path>) -> io::Result<File> {
        let path = path.as_ref().to_owned();
        spawn_blocking(move || std::fs::File::create(path))
            .await?
            .map(|f| File { inner: f })
    }

    /// Open with options
    pub fn options() -> OpenOptions {
        OpenOptions::new()
    }
}
```

### Step 2: OpenOptions Builder
```rust
pub struct OpenOptions {
    read: bool,
    write: bool,
    append: bool,
    truncate: bool,
    create: bool,
    create_new: bool,
    // Unix-specific
    #[cfg(unix)]
    mode: Option<u32>,
}

impl OpenOptions {
    pub fn new() -> Self {
        Self {
            read: false,
            write: false,
            append: false,
            truncate: false,
            create: false,
            create_new: false,
            #[cfg(unix)]
            mode: None,
        }
    }

    pub fn read(mut self, read: bool) -> Self { self.read = read; self }
    pub fn write(mut self, write: bool) -> Self { self.write = write; self }
    pub fn append(mut self, append: bool) -> Self { self.append = append; self }
    pub fn truncate(mut self, truncate: bool) -> Self { self.truncate = truncate; self }
    pub fn create(mut self, create: bool) -> Self { self.create = create; self }
    pub fn create_new(mut self, create_new: bool) -> Self { self.create_new = create_new; self }

    #[cfg(unix)]
    pub fn mode(mut self, mode: u32) -> Self { self.mode = Some(mode); self }

    pub async fn open(self, path: impl AsRef<Path>) -> io::Result<File> {
        let path = path.as_ref().to_owned();
        let opts = self;
        spawn_blocking(move || {
            let mut std_opts = std::fs::OpenOptions::new();
            std_opts.read(opts.read);
            std_opts.write(opts.write);
            std_opts.append(opts.append);
            std_opts.truncate(opts.truncate);
            std_opts.create(opts.create);
            std_opts.create_new(opts.create_new);
            #[cfg(unix)]
            if let Some(mode) = opts.mode {
                use std::os::unix::fs::OpenOptionsExt;
                std_opts.mode(mode);
            }
            std_opts.open(path)
        }).await?
        .map(|f| File { inner: f })
    }
}
```

